prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?allNode ?name ?type WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .
  { ?allNode a bboExt:ChoreographyTask . }
  UNION
  { ?allNode a bboExt:ExclusiveGateway . }
  UNION
  { ?allNode a bboExt:ParallelGateway . }
  UNION
  { ?allNode a bboExt:StartEvent . }
  UNION
  { ?allNode a bboExt:EndEvent . }
  ?allNode tai:belongsTo ?choreo .
  OPTIONAL { ?allNode bbo:name ?name . }
  ?allNode a ?type .
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?unreachable ?name ?type WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .

  # Get all nodes in the choreography
  { ?unreachable a bboExt:ChoreographyTask . }
  UNION { ?unreachable a bboExt:ExclusiveGateway . }
  UNION { ?unreachable a bboExt:ParallelGateway . }
  UNION { ?unreachable a bboExt:StartEvent . }
  UNION { ?unreachable a bboExt:EndEvent . }

  ?unreachable tai:belongsTo ?choreo .
  OPTIONAL { ?unreachable bbo:name ?name . }
  ?unreachable a ?type .

  # Exclude nodes reachable from start
  FILTER NOT EXISTS {
    ?start a bboExt:StartEvent .
    ?start tai:belongsTo ?choreo .
    ?start ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?unreachable .
  }
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?node ?name ?type WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .

  # Get all flow nodes
  { ?node a bboExt:ChoreographyTask . }
  UNION { ?node a bboExt:ExclusiveGateway . }
  UNION { ?node a bboExt:ParallelGateway . }
  UNION { ?node a bboExt:StartEvent . }
  UNION { ?node a bboExt:EndEvent . }

  ?node tai:belongsTo ?choreo .
  OPTIONAL { ?node bbo:name ?name . }
  ?node a ?type .

  # Find nodes with NO outgoing sequence flow (dead ends)
  FILTER NOT EXISTS {
    ?edge a bbo:SequenceFlow .
    ?edge bbo:has_sourceRef ?node .
  }
}
LIMIT 50

