prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?name ?dir (COUNT(?out) as ?outCount) (COUNT(?in) as ?inCount) WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .

  { ?gw a bboExt:ExclusiveGateway . }
  UNION { ?gw a bboExt:ParallelGateway . }

  ?gw tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?name . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?dir . }

  OPTIONAL { ?edge a bbo:SequenceFlow . ?edge bbo:has_sourceRef ?gw . BIND(?gw AS ?out) }
  OPTIONAL { ?edge a bbo:SequenceFlow . ?edge bbo:has_targetRef ?gw . BIND(?gw AS ?in) }
}
GROUP BY ?gw ?name ?dir
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?name ?dir (COUNT(?out) as ?outCount) (COUNT(?in) as ?inCount) WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .

  { ?gw a bboExt:ExclusiveGateway . }
  UNION { ?gw a bboExt:ParallelGateway . }
  UNION { ?gw a bboExt:EventBasedGateway . }

  ?gw tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?name . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?dir . }

  OPTIONAL { ?edge a bbo:SequenceFlow . ?edge bbo:has_sourceRef ?gw . BIND(1 AS ?out) }
  OPTIONAL { ?edge a bbo:SequenceFlow . ?edge bbo:has_targetRef ?gw . BIND(1 AS ?in) }
}
GROUP BY ?gw ?name ?dir
ORDER BY ?gw

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?dir (COUNT(DISTINCT ?outEdge) as ?outCount) (COUNT(DISTINCT ?inEdge) as ?inCount) WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .

  { ?gw a bboExt:ExclusiveGateway . }
  UNION { ?gw a bboExt:ParallelGateway . }
  UNION { ?gw a bboExt:EventBasedGateway . }

  ?gw tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?dir . }

  OPTIONAL { ?outEdge a bbo:SequenceFlow . ?outEdge bbo:has_sourceRef ?gw . }
  OPTIONAL { ?inEdge a bbo:SequenceFlow . ?inEdge bbo:has_targetRef ?gw . }
}
GROUP BY ?gw ?gwName ?dir
ORDER BY ?gw

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
# Check if there are any nodes that cannot reach the end (dead paths)
SELECT DISTINCT ?node ?name ?type WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .

  # Get all flow nodes (excluding end)
  { ?node a bboExt:ChoreographyTask . }
  UNION { ?node a bboExt:ExclusiveGateway . }
  UNION { ?node a bboExt:ParallelGateway . }
  UNION { ?node a bboExt:StartEvent . }

  ?node tai:belongsTo ?choreo .
  OPTIONAL { ?node bbo:name ?name . }
  ?node a ?type .

  # Find nodes that CANNOT reach the end
  FILTER NOT EXISTS {
    ?end a bboExt:EndEvent .
    ?end tai:belongsTo ?choreo .
    ?node ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?end .
  }
}
LIMIT 50

